const SectorStocks: React.FC = () => {
  const { sector } = useParams<{ sector: string }>();
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [stocks, setStocks] = useState<any[]>([]);

  useEffect(() => {
    if (sector) {
      fetchSectorStocks();
    }
  }, [sector]);

  const fetchSectorStocks = async () => {
    setLoading(true);
    setError(null);

    try {
      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 1000));

      const sectorData = mockIndianStocks[sector as keyof typeof mockIndianStocks] || [];
      setStocks(sectorData);
    } catch (err) {
      setError('Failed to fetch stock data. Please try again later.');
    } finally {
      setLoading(false);
    }
  };

  const filteredStocks = stocks.filter(stock =>
    stock.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    stock.symbol.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleAddToPortfolio = (stock: any) => {
    console.log('Adding to portfolio:', stock);
    // Future implementation: Add to user's portfolio
  };

  if (!sector) {
    return <div>Invalid sector</div>;
  }

  const sectorName = sector.charAt(0).toUpperCase() + sector.slice(1);

  return (
    <SectorStocksContainer>
      <PageHeader
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <SectorTitle>{sectorName} STOCKS</SectorTitle>
        <BackButton
          onClick={() => navigate('/stocks')}
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
        >
          ← Back to Sectors
        </BackButton>
      </PageHeader>

      <SearchContainer
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2, duration: 0.5 }}
      >
        <SearchInput
          type="text"
          placeholder={`Search Indian ${sectorName} companies (e.g., ${sector === 'it' ? 'HCL' : 'TATA'})`}
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
      </SearchContainer>

      {loading && (
        <LoadingState
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
        >
          <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>⏳</div>
          <p>Loading {sectorName} stocks data...</p>
        </LoadingState>
      )}

      {error && (
        <ErrorState
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
        >
          <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>⚠️</div>
          <p>{error}</p>
          <button 
            onClick={fetchSectorStocks}
            style={{ 
              marginTop: '1rem', 
              padding: '0.5rem 1rem', 
              background: '#ff6b6b', 
              border: 'none', 
              borderRadius: '5px', 
              color: 'white', 
              cursor: 'pointer' 
            }}
          >
            Retry
          </button>
        </ErrorState>
      )}

      {!loading && !error && (
        <ResultsContainer
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.4, duration: 0.5 }}
        >
          {filteredStocks.length > 0 ? (
            <StockTable>
              <thead>
                <tr>
                  <th>Company Name</th>
                  <th>Symbol</th>
                  <th>Current Price (₹)</th>
                  <th>Today's Change</th>
                  <th>Min Price</th>
                  <th>Max Price</th>
                  <th>P/E Ratio</th>
                  <th>Market Value</th>
                  <th>EPS (₹)</th>
                  <th>Opportunity</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {filteredStocks.map((stock, index) => (
                  <tr key={index}>
                    <td>{stock.name}</td>
                    <td>{stock.symbol}</td>
                    <td>{stock.price.toLocaleString('en-IN')}</td>
                    <td style={{ color: stock.change >= 0 ? '#4caf50' : '#f44336' }}>
                      {stock.change >= 0 ? '+' : ''}{stock.change}
                    </td>
                    <td>{stock.min.toLocaleString('en-IN')}</td>
                    <td>{stock.max.toLocaleString('en-IN')}</td>
                    <td>{stock.pe}</td>
                    <td>₹{stock.mcv.toLocaleString('en-IN')} Cr</td>
                    <td>{stock.eps}</td>
                    <td>
                      <OpportunityBadge opportunity={stock.opportunity}>
                        {stock.opportunity}
                      </OpportunityBadge>
                    </td>
                    <td>
                      <AddButton onClick={() => handleAddToPortfolio(stock)}>
                        Add
                      </AddButton>
                    </td>
                  </tr>
                ))}
              </tbody>
            </StockTable>
          ) : (
            <div style={{ textAlign: 'center', padding: '2rem', color: '#cccccc' }}>
              <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🔍</div>
              <p>No stocks found matching your search criteria.</p>
            </div>
          )}
        </ResultsContainer>
      )}
    </SectorStocksContainer>
  );
};

